const crypto = require('crypto');
const secret = '73f0b54afa26320af143b62794ca2c4c';
const headers = items[0].json.headers;
const body = items[0].json.body;
const signature = headers['x-luna-signature'];

const hmac = crypto.createHmac('sha256', secret);
hmac.update(JSON.stringify(body));
const expectedSignature = hmac.digest('hex');

if (signature !== expectedSignature) {
  return [{ json: { error: 'Invalid HMAC Signature' } }];
}

return [{ json: { status: 'authorized', payload: body } }];
